//! Bitmap font (5x7).
pub const CHAR_WIDTH: u32 = 5;
pub const CHAR_HEIGHT: u32 = 7;
pub const CHAR_GAP: u32 = 1;
pub fn char_bitmap(ch: char) -> [u8; 7] {
    match ch {
        'A'=>[0b01110,0b10001,0b10001,0b11111,0b10001,0b10001,0b10001],'B'=>[0b11110,0b10001,0b10001,0b11110,0b10001,0b10001,0b11110],'C'=>[0b01110,0b10001,0b10000,0b10000,0b10000,0b10001,0b01110],'D'=>[0b11110,0b10001,0b10001,0b10001,0b10001,0b10001,0b11110],'E'=>[0b11111,0b10000,0b10000,0b11110,0b10000,0b10000,0b11111],'F'=>[0b11111,0b10000,0b10000,0b11110,0b10000,0b10000,0b10000],'G'=>[0b01110,0b10001,0b10000,0b10111,0b10001,0b10001,0b01110],'H'=>[0b10001,0b10001,0b10001,0b11111,0b10001,0b10001,0b10001],'I'=>[0b01110,0b00100,0b00100,0b00100,0b00100,0b00100,0b01110],'J'=>[0b00111,0b00010,0b00010,0b00010,0b00010,0b10010,0b01100],'K'=>[0b10001,0b10010,0b10100,0b11000,0b10100,0b10010,0b10001],'L'=>[0b10000,0b10000,0b10000,0b10000,0b10000,0b10000,0b11111],'M'=>[0b10001,0b11011,0b10101,0b10101,0b10001,0b10001,0b10001],'N'=>[0b10001,0b11001,0b10101,0b10011,0b10001,0b10001,0b10001],'O'=>[0b01110,0b10001,0b10001,0b10001,0b10001,0b10001,0b01110],'P'=>[0b11110,0b10001,0b10001,0b11110,0b10000,0b10000,0b10000],'Q'=>[0b01110,0b10001,0b10001,0b10001,0b10101,0b10010,0b01101],'R'=>[0b11110,0b10001,0b10001,0b11110,0b10100,0b10010,0b10001],'S'=>[0b01110,0b10001,0b10000,0b01110,0b00001,0b10001,0b01110],'T'=>[0b11111,0b00100,0b00100,0b00100,0b00100,0b00100,0b00100],'U'=>[0b10001,0b10001,0b10001,0b10001,0b10001,0b10001,0b01110],'V'=>[0b10001,0b10001,0b10001,0b10001,0b10001,0b01010,0b00100],'W'=>[0b10001,0b10001,0b10001,0b10101,0b10101,0b11011,0b10001],'X'=>[0b10001,0b10001,0b01010,0b00100,0b01010,0b10001,0b10001],'Y'=>[0b10001,0b10001,0b01010,0b00100,0b00100,0b00100,0b00100],'Z'=>[0b11111,0b00001,0b00010,0b00100,0b01000,0b10000,0b11111],
        'a'=>[0b00000,0b00000,0b01110,0b00001,0b01111,0b10001,0b01111],'b'=>[0b10000,0b10000,0b11110,0b10001,0b10001,0b10001,0b11110],'c'=>[0b00000,0b00000,0b01110,0b10000,0b10000,0b10001,0b01110],'d'=>[0b00001,0b00001,0b01111,0b10001,0b10001,0b10001,0b01111],'e'=>[0b00000,0b00000,0b01110,0b10001,0b11111,0b10000,0b01110],'f'=>[0b00110,0b01001,0b01000,0b11100,0b01000,0b01000,0b01000],'g'=>[0b00000,0b00000,0b01111,0b10001,0b01111,0b00001,0b01110],'h'=>[0b10000,0b10000,0b10110,0b11001,0b10001,0b10001,0b10001],'i'=>[0b00100,0b00000,0b01100,0b00100,0b00100,0b00100,0b01110],'j'=>[0b00010,0b00000,0b00110,0b00010,0b00010,0b10010,0b01100],'k'=>[0b10000,0b10000,0b10010,0b10100,0b11000,0b10100,0b10010],'l'=>[0b01100,0b00100,0b00100,0b00100,0b00100,0b00100,0b01110],'m'=>[0b00000,0b00000,0b11010,0b10101,0b10101,0b10101,0b10001],'n'=>[0b00000,0b00000,0b10110,0b11001,0b10001,0b10001,0b10001],'o'=>[0b00000,0b00000,0b01110,0b10001,0b10001,0b10001,0b01110],'p'=>[0b00000,0b00000,0b11110,0b10001,0b11110,0b10000,0b10000],'q'=>[0b00000,0b00000,0b01111,0b10001,0b01111,0b00001,0b00001],'r'=>[0b00000,0b00000,0b10110,0b11001,0b10000,0b10000,0b10000],'s'=>[0b00000,0b00000,0b01110,0b10000,0b01110,0b00001,0b11110],'t'=>[0b01000,0b01000,0b11100,0b01000,0b01000,0b01001,0b00110],'u'=>[0b00000,0b00000,0b10001,0b10001,0b10001,0b10011,0b01101],'v'=>[0b00000,0b00000,0b10001,0b10001,0b10001,0b01010,0b00100],'w'=>[0b00000,0b00000,0b10001,0b10001,0b10101,0b10101,0b01010],'x'=>[0b00000,0b00000,0b10001,0b01010,0b00100,0b01010,0b10001],'y'=>[0b00000,0b00000,0b10001,0b10001,0b01111,0b00001,0b01110],'z'=>[0b00000,0b00000,0b11111,0b00010,0b00100,0b01000,0b11111],
        '0'=>[0b01110,0b10001,0b10011,0b10101,0b11001,0b10001,0b01110],'1'=>[0b00100,0b01100,0b00100,0b00100,0b00100,0b00100,0b01110],'2'=>[0b01110,0b10001,0b00001,0b00110,0b01000,0b10000,0b11111],'3'=>[0b01110,0b10001,0b00001,0b00110,0b00001,0b10001,0b01110],'4'=>[0b00010,0b00110,0b01010,0b10010,0b11111,0b00010,0b00010],'5'=>[0b11111,0b10000,0b11110,0b00001,0b00001,0b10001,0b01110],'6'=>[0b01110,0b10000,0b11110,0b10001,0b10001,0b10001,0b01110],'7'=>[0b11111,0b00001,0b00010,0b00100,0b01000,0b01000,0b01000],'8'=>[0b01110,0b10001,0b10001,0b01110,0b10001,0b10001,0b01110],'9'=>[0b01110,0b10001,0b10001,0b01111,0b00001,0b00001,0b01110],
        '.'=>[0b00000,0b00000,0b00000,0b00000,0b00000,0b00000,0b00100],','=>[0b00000,0b00000,0b00000,0b00000,0b00000,0b00100,0b01000],'!'=>[0b00100,0b00100,0b00100,0b00100,0b00100,0b00000,0b00100],'?'=>[0b01110,0b10001,0b00001,0b00010,0b00100,0b00000,0b00100],':'=>[0b00000,0b00100,0b00000,0b00000,0b00000,0b00100,0b00000],';'=>[0b00000,0b00100,0b00000,0b00000,0b00000,0b00100,0b01000],'-'=>[0b00000,0b00000,0b00000,0b11111,0b00000,0b00000,0b00000],'_'=>[0b00000,0b00000,0b00000,0b00000,0b00000,0b00000,0b11111],'+'=>[0b00000,0b00100,0b00100,0b11111,0b00100,0b00100,0b00000],'='=>[0b00000,0b00000,0b11111,0b00000,0b11111,0b00000,0b00000],'('=>[0b00010,0b00100,0b01000,0b01000,0b01000,0b00100,0b00010],')'=>[0b01000,0b00100,0b00010,0b00010,0b00010,0b00100,0b01000],'/'=>[0b00001,0b00010,0b00010,0b00100,0b01000,0b01000,0b10000],
        '\\'=>[0b10000,0b01000,0b01000,0b00100,0b00010,0b00010,0b00001],'\''=>[0b00100,0b00100,0b01000,0b00000,0b00000,0b00000,0b00000],'"'=>[0b01010,0b01010,0b10100,0b00000,0b00000,0b00000,0b00000],'@'=>[0b01110,0b10001,0b10111,0b10101,0b10111,0b10000,0b01110],'#'=>[0b01010,0b01010,0b11111,0b01010,0b11111,0b01010,0b01010],'$'=>[0b00100,0b01111,0b10100,0b01110,0b00101,0b11110,0b00100],'%'=>[0b11001,0b11001,0b00010,0b00100,0b01000,0b10011,0b10011],'&'=>[0b01100,0b10010,0b10100,0b01000,0b10101,0b10010,0b01101],'*'=>[0b00000,0b00100,0b10101,0b01110,0b10101,0b00100,0b00000],'<'=>[0b00010,0b00100,0b01000,0b10000,0b01000,0b00100,0b00010],'>'=>[0b01000,0b00100,0b00010,0b00001,0b00010,0b00100,0b01000],'['=>[0b01110,0b01000,0b01000,0b01000,0b01000,0b01000,0b01110],']'=>[0b01110,0b00010,0b00010,0b00010,0b00010,0b00010,0b01110],'{'=>[0b00110,0b00100,0b00100,0b01000,0b00100,0b00100,0b00110],'}'=>[0b01100,0b00100,0b00100,0b00010,0b00100,0b00100,0b01100],'~'=>[0b00000,0b00000,0b01000,0b10101,0b00010,0b00000,0b00000],'`'=>[0b01000,0b00100,0b00010,0b00000,0b00000,0b00000,0b00000],'^'=>[0b00100,0b01010,0b10001,0b00000,0b00000,0b00000,0b00000],'|'=>[0b00100,0b00100,0b00100,0b00100,0b00100,0b00100,0b00100],' '=>[0b00000,0b00000,0b00000,0b00000,0b00000,0b00000,0b00000],
        _=>[0b11111,0b10001,0b10001,0b10001,0b10001,0b10001,0b11111],
    }
}
pub fn text_width(text: &str, scale: u32) -> u32 { let sc = scale.max(1); let n = text.len() as u32; if n == 0 { 0 } else { n * CHAR_WIDTH * sc + (n - 1) * CHAR_GAP * sc } }
pub fn text_height(text: &str, scale: u32) -> u32 { let sc = scale.max(1); let l = text.split('\n').count() as u32; if l == 0 { 0 } else { l * CHAR_HEIGHT * sc + (l - 1) * CHAR_GAP * sc } }
pub fn has_glyph(ch: char) -> bool { matches!(ch, 'A'..='Z'|'a'..='z'|'0'..='9'|'.'|','|'!'|'?'|':'|';'|'-'|'_'|'+'|'='|'('|')'|'/'|'\\'|'\''|'"'|'@'|'#'|'$'|'%'|'&'|'*'|'<'|'>'|'['|']'|'{'|'}'|'~'|'`'|'^'|'|'|' ') }
#[cfg(test)] mod tests { use super::*;
    #[test] fn upper() { for c in 'A'..='Z' { assert!(has_glyph(c)); assert!(char_bitmap(c).iter().any(|&r| r!=0)); } }
    #[test] fn lower() { for c in 'a'..='z' { assert!(has_glyph(c)); assert!(char_bitmap(c).iter().any(|&r| r!=0)); } }
    #[test] fn digits() { for c in '0'..='9' { assert!(has_glyph(c)); assert!(char_bitmap(c).iter().any(|&r| r!=0)); } }
    #[test] fn punct() { for c in ".,!?:;-_+=()".chars() { assert!(has_glyph(c)); } }
    #[test] fn space() { assert!(char_bitmap(' ').iter().all(|&r| r==0)); }
    #[test] fn widths() { assert_eq!(text_width("",1),0); assert_eq!(text_width("A",1),5); assert_eq!(text_width("ABC",1),17); assert_eq!(text_width("AB",2),22); }
    #[test] fn heights() { assert_eq!(text_height("Hi",1),7); assert_eq!(text_height("A\nB",1),15); assert_eq!(text_height("A\nB",2),30); }
    #[test] fn bits() { for c in ('A'..='Z').chain('a'..='z').chain('0'..='9').chain(" .,!?:;-_+=()".chars()) { for &r in &char_bitmap(c) { assert!(r<=0b11111); } } }
}
